class ParkingSystem {
public:
    ParkingSystem(int big, int medium, int small) {
        bigSlots = big;
        mediumSlots = medium;
        smallSlots = small;
    }

    bool addCar(int carType) {
        if (carType == 1) {
            if (bigSlots > 0) {
                bigSlots--;
                return true;
            }
        } else if (carType == 2) {
            if (mediumSlots > 0) {
                mediumSlots--;
                return true;
            }
        } else {
            if (smallSlots > 0) {
                smallSlots--;
                return true;
            }
        }
        return false;
    }

    int getSlotsLeft() {
        int slotsLeft = bigSlots + mediumSlots + smallSlots;
        return slotsLeft;
    }
};
```

